                                }
                        }
                        continue
                }
                if err := os.MkdirAll(filepath.Dir(target), 0o755); err != nil {
                        return err
                }
                key := d3.KeyFor(row, profile)
                if existing, ok := groups[key]; ok {
                        _ = os.Remove(target)
                        if err := os.Link(existing, target); err != nil {
                                return err
                        }
                        continue
                }
                if strings.TrimSpace(row.Op) == "" || row.Op == "write" {
